#include <gtest/gtest.h>

#include "query_employee_hierarchy.hpp"

namespace query_employee_hierarchy {

TEST(sqlite, query_employee_hierarchy) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Employee>(conn);
  create_table<Employee>(conn);

  Employee ceo{.emp_id = 1, .name = "CEO", .manager_id = std::nullopt};
  Employee mgr{.emp_id = 2, .name = "Manager", .manager_id = 1};
  Employee dev{.emp_id = 3, .name = "Developer", .manager_id = 2};

  insert(conn, std::vector{ceo, mgr, dev});

  auto rows = query_employee_hierarchy();

  ASSERT_EQ(rows.size(), 3);

  auto find = [&](const std::string& n) -> std::optional<EmployeeManager> {
    for (const auto& r : rows) {
      if (r.employee == n) return r;
    }
    return std::nullopt;
  };

  auto r_ceo = find("CEO").value();
  EXPECT_FALSE(r_ceo.manager.has_value());

  auto r_mgr = find("Manager").value();
  ASSERT_TRUE(r_mgr.manager.has_value());
  EXPECT_EQ(r_mgr.manager.value(), "CEO");

  auto r_dev = find("Developer").value();
  ASSERT_TRUE(r_dev.manager.has_value());
  EXPECT_EQ(r_dev.manager.value(), "Manager");
}

