/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = *conn_result;

    // Build the base query
    auto query = sqlgen::select_from<Book>(
        "book_id"_c, "title"_c, "author"_c, "year"_c, "genre"_c, "price"_c
    );

    // Build WHERE conditions dynamically
    auto conditions = rfl::Tuple{};

    if (filters.title_keyword) {
        conditions = rfl::tuple_cat(
            conditions,
            "title"_c.like("%" + *filters.title_keyword + "%")
        );
    }

    if (filters.min_year) {
        conditions = rfl::tuple_cat(
            conditions,
            "year"_c >= *filters.min_year
        );
    }

    if (filters.genre) {
        conditions = rfl::tuple_cat(
            conditions,
            "genre"_c == *filters.genre
        );
    }

    if (filters.max_price) {
        conditions = rfl::tuple_cat(
            conditions,
            "price"_c <= *filters.max_price
        );
    }

    // Apply WHERE clause if any conditions were added
    if (conditions.size() > 0) {
        query = query | sqlgen::where(conditions);
    }

    // Execute the query and return results
    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Query execution failed");
    }

    return *result;
}

