  // 2. Create temporary table for Event structure
  auto create_table_stmt = sqlgen::create_table<Event> | sqlgen::if_not_exists;
  auto create_result = create_table_stmt(conn);
  if (!create_result) {
    throw std::runtime_error("Failed to create table");
  }

  // 3. Insert events into the temporary table
  auto insert_stmt = sqlgen::insert_into<Event>(events);
  auto insert_result = insert_stmt(conn);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert events");
  }

  // 4. Build and execute the query with temporal operations
  auto query = sqlgen::select_from<Event>(
      "event_id"_c,
      "event_name"_c,
      sqlgen::day("start_time"_c).as<"start_day">,
      sqlgen::month("start_time"_c).as<"start_month">,
      sqlgen::year("start_time"_c).as<"start_year">,
      sqlgen::hour("start_time"_c).as<"start_hour">,
      sqlgen::minute("start_time"_c).as<"start_minute">,
      sqlgen::second("start_time"_c).as<"start_second">,
      sqlgen::weekday("start_time"_c).as<"start_weekday">,
      sqlgen::unixepoch("start_time"_c).as<"start_epoch">,
      sqlgen::days_between("start_time"_c, "end_time"_c).as<"duration_days">
  ) | sqlgen::where("end_time"_c.is_not_null());

  // 5. Execute query and map results to TemporalAnalysis
  auto result = query(conn);
  if (!result) {
    throw std::runtime_error("Query execution failed");
  }

  // 6. Return the analysis results
  return result.value();
}

