      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2, 
      "salary"_t2
  ).inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
   .to<std::vector<JoinResult>>;

  auto inner_results = inner_query(conn);
  if (!inner_results) {
    throw std::runtime_error("Failed to execute INNER JOIN query");
  }

  // 4. Perform LEFT JOIN using sqlgen's join functionality
  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2, 
      "salary"_t2
  ).left_join<Department, "d">("department_id"_t2 == "department_id"_t1)
   .to<std::vector<JoinResult>>;

  auto left_results = left_query(conn);
  if (!left_results) {
    throw std::runtime_error("Failed to execute LEFT JOIN query");
  }

  // 5. Perform RIGHT JOIN using sqlgen's join functionality  
  auto right_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2, 
      "salary"_t2
  ).right_join<Department, "d">("department_id"_t2 == "department_id"_t1)
   .to<std::vector<JoinResult>>;

  auto right_results = right_query(conn);
  if (!right_results) {
    throw std::runtime_error("Failed to execute RIGHT JOIN query");
  }

  // 6. Perform FULL JOIN using sqlgen's join functionality
  auto full_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2, 
      "salary"_t2
  ).full_join<Department, "d">("department_id"_t2 == "department_id"_t1)
   .to<std::vector<JoinResult>>;

  auto full_results = full_query(conn);
  if (!full_results) {
    throw std::runtime_error("Failed to execute FULL JOIN query");
  }

  // 7. Collect results into appropriate data structures
