template <class ValueType, class... Args>
inline auto create_or_replace_view_as(const SelectFrom<Args...>& _as) {
  static_assert(
      transpilation::get_table_or_view<ValueType>() ==
          dynamic::TableOrView::view,
      "Only views can be created using create_or_replace_view_as(...), "
      "not tables. To declare a struct a view, "
      "simply add 'static constexpr bool is_view = true;' to the struct "
      "declaration.");
  return CreateAs<std::remove_cvref_t<ValueType>, Args...>{
      .what_ = dynamic::TableOrView::view,
      .as_ = _as,
      .or_replace_ = true,
      .if_not_exists_ = false};
}

template <rfl::internal::StringLiteral _name>
auto count_distinct(const Col<_name>&) {
  return transpilation::Aggregation<transpilation::AggregationOp::count,
                                    transpilation::Col<_name>>{
      .val = transpilation::Col<_name>{}, .distinct = true};
}

template <class... ColTypes>
auto group_by(const ColTypes&...) {
  return GroupBy<ColTypes...>{};
};

template <rfl::internal::StringLiteral _alias, class QueryType,
          class ConditionType>
auto inner_join(const QueryType& _query, const ConditionType& _on) {
  return join<_alias, transpilation::JoinType::inner_join>(_query, _on);
}

template <class... ColTypes>
friend auto operator|(const Read& _r, const OrderBy<ColTypes...>&) {
  static_assert(
      std::is_same_v<OrderByType, Nothing>,
      "You cannot call order_by(...) twice (but you can order by more "
      "than one column).");
  static_assert(std::is_same_v<LimitType, Nothing>,
                "You cannot call limit(...) before order_by.");
  static_assert(sizeof...(ColTypes) != 0,
                "You must assign at least one column to order by(...).");
  return Read<Type, WhereType,
              transpilation::order_by_t<
                  transpilation::value_t<Type>, Nothing,
                  typename std::remove_cvref_t<ColTypes>::ColType...>,
              LimitType>{.where_ = _r.where_};
}

